from __future__ import annotations

import base64
import gzip
import subprocess
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
PATCH_B64 = ""
TEST_B64 = ""
CI_B64 = ""


def _decode(value: str) -> bytes:
    return gzip.decompress(base64.b64decode(value))


def main() -> None:
    patch = _decode(PATCH_B64)
    subprocess.run(["git", "apply", "--check", "-"], cwd=ROOT, input=patch, check=True)
    subprocess.run(["git", "apply", "-"], cwd=ROOT, input=patch, check=True)

    test_path = ROOT / "backend/tests/test_token_flow_execution_wiring.py"
    test_path.write_bytes(_decode(TEST_B64))
    (ROOT / ".github/workflows/ci.yml").write_bytes(_decode(CI_B64))
    Path(__file__).unlink()


if __name__ == "__main__":
    main()
